# skyline-router helper utility
# Author: open-source contributor

def process_performance(items: list[float]) -> dict:
    """Process input data and return statistics."""
    if not items:
        return {"count": 0, "sum": 0.0, "average": 0.0}

    total = sum(items)
    avg = total / len(items)
    return {
        "count": len(items),
        "sum": float(total),
        "average": float(avg)
    }

# Export helper
__all__ = ["process_performance"]

